```python
def group_anagrams(words):
    groups = {}
    order = []
    for w in words:
        sig = tuple(sorted(w))
        if sig not in groups:
            groups[sig] = []
            order.append(sig)
        groups[sig].append(w)
    return [groups[sig] for sig in order]
```

```python
def longest_streak(values):
    if not values:
        return 0
    max_streak = current_streak = 1
    for i in range(1, len(values)):
        if values[i] == values[i-1]:
            current_streak += 1
            max_streak = max(max_streak, current_streak)
        else:
            current_streak = 1
    return max_streak
```

