def parse_settings(lines):
    result = {}
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        if '=' not in stripped:
            raise ValueError(f"Line without '=': {stripped!r}")
        key, sep, value = stripped.partition('=')
        key = key.strip()
        if not key:
            raise ValueError(f"Empty key in line: {stripped!r}")
        result[key] = value
    return result
```
